 {"id":"asupersync-2spzv","title":"[TLS] Implement TlsStream with AsyncRead/AsyncWrite","description":"## Overview

Implement the `TlsStream` type that wraps a transport stream and implements `AsyncRead` + `AsyncWrite` with TLS encryption.

## Rationale

The TlsStream is the core abstraction that:
- Transparently encrypts/decrypts data
- Handles the TLS handshake
- Provides access to connection metadata (ALPN, certs, etc.)
- Manages graceful shutdown

## Implementation

### TlsStream

```rust
// tls/src/stream.rs

use std::io;
use std::pin::Pin;
use std::task::{Context, Poll};
use tokio::io::{AsyncRead, AsyncWrite, ReadBuf};
use rustls::{Connection, ConnectionCommon, ServerConnection, ClientConnection};

use crate::TlsError;

/// Internal state of the TLS stream.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TlsState {
    /// Handshake in progress.
    Handshaking,
    /// TLS session is established.
    Ready,
    /// Shutdown initiated.
    ShuttingDown,
    /// Connection is closed.
    Closed,
}

/// A TLS stream wrapping an underlying async transport.
pub struct TlsStream<IO> {
    io: IO,
    conn: TlsConnection,
    state: TlsState,
}

// Wrapper to handle both client and server connections
enum TlsConnection {
    Client(ClientConnection),
    Server(ServerConnection),
}

impl TlsConnection {
    fn is_handshaking(&self) -> bool {
        match self {
            TlsConnection::Client(c) => c.is_handshaking(),
            TlsConnection::Server(s) => s.is_handshaking(),
        }
    }

    fn wants_read(&self) -> bool {
        match self {
            TlsConnection::Client(c) => c.wants_read(),
            TlsConnection::Server(s) => s.wants_read(),
        }
    }

    fn wants_write(&self) -> bool {
        match self {
            TlsConnection::Client(c) => c.wants_write(),
            TlsConnection::Server(s) => s.wants_write(),
        }
    }

    fn reader(&mut self) -> rustls::Reader<'_> {
        match self {
            TlsConnection::Client(c) => c.reader(),
            TlsConnection::Server(s) => s.reader(),
        }
    }

    fn writer(&mut self) -> rustls::Writer<'_> {
        match self {
            TlsConnection::Client(c) => c.writer(),
            TlsConnection::Server(s) => s.writer(),
        }
    }

    fn read_tls(&mut self, rd: &mut dyn io::Read) -> io::Result<usize> {
        match self {
            TlsConnection::Client(c) => c.read_tls(rd),
            TlsConnection::Server(s) => s.read_tls(rd),
        }
    }

    fn write_tls(&mut self, wr: &mut dyn io::Write) -> io::Result<usize> {
        match self {
            TlsConnection::Client(c) => c.write_tls(wr),
            TlsConnection::Server(s) => s.write_tls(wr),
        }
    }

    fn process_new_packets(&mut self) -> Result<rustls::IoState, rustls::Error> {
        match self {
            TlsConnection::Client(c) => c.process_new_packets(),
            TlsConnection::Server(s) => s.process_new_packets(),
        }
    }

    fn send_close_notify(&mut self) {
        match self {
            TlsConnection::Client(c) => c.send_close_notify(),
            TlsConnection::Server(s) => s.send_close_notify(),
        }
    }

    fn protocol_version(&self) -> Option<rustls::ProtocolVersion> {
        match self {
            TlsConnection::Client(c) => c.protocol_version(),
            TlsConnection::Server(s) => s.protocol_version(),
        }
    }

    fn alpn_protocol(&self) -> Option<&[u8]> {
        match self {
            TlsConnection::Client(c) => c.alpn_protocol(),
            TlsConnection::Server(s) => s.alpn_protocol(),
        }
    }

    fn peer_certificates(&self) -> Option<&[rustls::Certificate]> {
        match self {
            TlsConnection::Client(c) => c.peer_certificates(),
            TlsConnection::Server(s) => s.peer_certificates(),
        }
    }

    fn sni_hostname(&self) -> Option<&str> {
        match self {
            TlsConnection::Client(_) => None,
            TlsConnection::Server(s) => s.sni_hostname(),
        }
    }
}

impl<IO> TlsStream<IO> {
    /// Create a new client TLS stream.
    pub(crate) fn new_client(io: IO, conn: ClientConnection) -> Self {
        TlsStream {
            io,
            conn: TlsConnection::Client(conn),
            state: TlsState::Handshaking,
        }
    }

    /// Create a new server TLS stream.
    pub(crate) fn new_server(io: IO, conn: ServerConnection) -> Self {
        TlsStream {
            io,
            conn: TlsConnection::Server(conn),
            state: TlsState::Handshaking,
        }
    }

    /// Get the negotiated ALPN protocol.
    pub fn alpn_protocol(&self) -> Option<&[u8]> {
        self.conn.alpn_protocol()
    }

    /// Get peer certificates (if any).
    pub fn peer_certificates(&self) -> Option<&[rustls::Certificate]> {
        self.conn.peer_certificates()
    }

    /// Get the TLS protocol version.
    pub fn protocol_version(&self) -> Option<rustls::ProtocolVersion> {
        self.conn.protocol_version()
    }

    /// Get the SNI hostname (server-side only).
    pub fn sni_hostname(&self) -> Option<&str> {
        self.conn.sni_hostname()
    }

    /// Get a reference to the underlying IO.
    pub fn get_ref(&self) -> &IO {
        &self.io
    }

    /// Get a mutable reference to the underlying IO.
    pub fn get_mut(&mut self) -> &mut IO {
        &mut self.io
    }

    /// Destructure into underlying IO (discards TLS state).
    pub fn into_inner(self) -> IO {
        self.io
    }
}

impl<IO: AsyncRead + AsyncWrite + Unpin> TlsStream<IO> {
    /// Perform the TLS handshake.
    pub(crate) async fn handshake(&mut self) -> Result<(), TlsError> {
        use futures_util::future::poll_fn;

        tracing::debug!("Starting TLS handshake");

        poll_fn(|cx| self.poll_handshake(cx)).await
    }

    fn poll_handshake(&mut self, cx: &mut Context<'_>) -> Poll<Result<(), TlsError>> {
        loop {
            // Process any pending TLS data
            if let Err(e) = self.conn.process_new_packets() {
                tracing::error!(error = %e, "TLS error during handshake");
                return Poll::Ready(Err(TlsError::Handshake(e.to_string())));
            }

            // Check if handshake is complete
            if !self.conn.is_handshaking() {
                self.state = TlsState::Ready;
                tracing::debug!("TLS handshake complete");
                return Poll::Ready(Ok(()));
            }

            // Write TLS data if we have any
            while self.conn.wants_write() {
                match self.poll_write_tls(cx) {
                    Poll::Ready(Ok(0)) => {
                        return Poll::Ready(Err(TlsError::Handshake(
                            "connection closed during handshake".into()
                        )));
                    }
                    Poll::Ready(Ok(_)) => continue,
                    Poll::Ready(Err(e)) => {
                        return Poll::Ready(Err(TlsError::Io(e)));
                    }
                    Poll::Pending => break,
                }
            }

            // Read TLS data if expected
            if self.conn.wants_read() {
                match self.poll_read_tls(cx) {
                    Poll::Ready(Ok(0)) => {
                        return Poll::Ready(Err(TlsError::Handshake(
                            "connection closed during handshake".into()
                        )));
                    }
                    Poll::Ready(Ok(_)) => continue,
                    Poll::Ready(Err(e)) => {
                        return Poll::Ready(Err(TlsError::Io(e)));
                    }
                    Poll::Pending => return Poll::Pending,
                }
            }
        }
    }

    fn poll_read_tls(&mut self, cx: &mut Context<'_>) -> Poll<io::Result<usize>> {
        struct AsyncReadAdapter<'a, 'b, IO> {
            io: &'a mut IO,
            cx: &'a mut Context<'b>,
        }

        impl<'a, 'b, IO: AsyncRead + Unpin> io::Read for AsyncReadAdapter<'a, 'b, IO> {
            fn read(&mut self, buf: &mut [u8]) -> io::Result<usize> {
                let mut read_buf = ReadBuf::new(buf);
                match Pin::new(&mut self.io).poll_read(self.cx, &mut read_buf) {
                    Poll::Ready(Ok(())) => Ok(read_buf.filled().len()),
                    Poll::Ready(Err(e)) => Err(e),
                    Poll::Pending => Err(io::ErrorKind::WouldBlock.into()),
                }
            }
        }

        let mut adapter = AsyncReadAdapter {
            io: &mut self.io,
            cx,
        };

        match self.conn.read_tls(&mut adapter) {
            Ok(n) => Poll::Ready(Ok(n)),
            Err(e) if e.kind() == io::ErrorKind::WouldBlock => Poll::Pending,
            Err(e) => Poll::Ready(Err(e)),
        }
    }

    fn poll_write_tls(&mut self, cx: &mut Context<'_>) -> Poll<io::Result<usize>> {
        struct AsyncWriteAdapter<'a, 'b, IO> {
            io: &'a mut IO,
            cx: &'a mut Context<'b>,
        }

        impl<'a, 'b, IO: AsyncWrite + Unpin> io::Write for AsyncWriteAdapter<'a, 'b, IO> {
            fn write(&mut self, buf: &[u8]) -> io::Result<usize> {
                match Pin::new(&mut self.io).poll_write(self.cx, buf) {
                    Poll::Ready(Ok(n)) => Ok(n),
                    Poll::Ready(Err(e)) => Err(e),
                    Poll::Pending => Err(io::ErrorKind::WouldBlock.into()),
                }
            }

            fn flush(&mut self) -> io::Result<()> {
                match Pin::new(&mut self.io).poll_flush(self.cx) {
                    Poll::Ready(Ok(())) => Ok(()),
                    Poll::Ready(Err(e)) => Err(e),
                    Poll::Pending => Err(io::ErrorKind::WouldBlock.into()),
                }
            }
        }

        let mut adapter = AsyncWriteAdapter {
            io: &mut self.io,
            cx,
        };

        match self.conn.write_tls(&mut adapter) {
            Ok(n) => Poll::Ready(Ok(n)),
            Err(e) if e.kind() == io::ErrorKind::WouldBlock => Poll::Pending,
            Err(e) => Poll::Ready(Err(e)),
        }
    }

    /// Gracefully shut down the TLS session.
    pub async fn shutdown(&mut self) -> Result<(), TlsError> {
        use futures_util::future::poll_fn;

        if self.state == TlsState::Closed {
            return Ok(());
        }

        tracing::debug!("Initiating TLS shutdown");
        self.state = TlsState::ShuttingDown;
        self.conn.send_close_notify();

        // Flush the close_notify
        poll_fn(|cx| {
            while self.conn.wants_write() {
                match self.poll_write_tls(cx) {
                    Poll::Ready(Ok(0)) => break,
                    Poll::Ready(Ok(_)) => continue,
                    Poll::Ready(Err(e)) => return Poll::Ready(Err(TlsError::Io(e))),
                    Poll::Pending => return Poll::Pending,
                }
            }
            Poll::Ready(Ok(()))
        }).await?;

        self.state = TlsState::Closed;
        tracing::debug!("TLS shutdown complete");
        Ok(())
    }
}

impl<IO: AsyncRead + AsyncWrite + Unpin> AsyncRead for TlsStream<IO> {
    fn poll_read(
        mut self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &mut ReadBuf<'_>,
    ) -> Poll<io::Result<()>> {
        if self.state == TlsState::Closed {
            return Poll::Ready(Ok(()));
        }

        // Read from the TLS session
        loop {
            // Try to read from the decrypted buffer
            let before = buf.filled().len();
            match self.conn.reader().read(buf.initialize_unfilled()) {
                Ok(n) => {
                    buf.advance(n);
                    if n > 0 {
                        tracing::trace!(bytes = n, "TLS read");
                        return Poll::Ready(Ok(()));
                    }
                }
                Err(e) if e.kind() == io::ErrorKind::WouldBlock => {}
                Err(e) => return Poll::Ready(Err(e)),
            }

            // Need more data - read from underlying IO
            match self.poll_read_tls(cx) {
                Poll::Ready(Ok(0)) => {
                    // EOF
                    return Poll::Ready(Ok(()));
                }
                Poll::Ready(Ok(_)) => {
                    // Process the new TLS data
                    if let Err(e) = self.conn.process_new_packets() {
                        return Poll::Ready(Err(io::Error::new(
                            io::ErrorKind::InvalidData,
                            e.to_string(),
                        )));
                    }
                    continue;
                }
                Poll::Ready(Err(e)) => return Poll::Ready(Err(e)),
                Poll::Pending => return Poll::Pending,
            }
        }
    }
}

impl<IO: AsyncRead + AsyncWrite + Unpin> AsyncWrite for TlsStream<IO> {
    fn poll_write(
        mut self: Pin<&mut Self>,
        cx: &mut Context<'_>,
        buf: &[u8],
    ) -> Poll<io::Result<usize>> {
        if self.state == TlsState::Closed {
            return Poll::Ready(Err(io::Error::new(
                io::ErrorKind::BrokenPipe,
                "TLS session closed",
            )));
        }

        // Write to the TLS session
        let n = self.conn.writer().write(buf)?;
        tracing::trace!(bytes = n, "TLS write");

        // Flush encrypted data to underlying IO
        while self.conn.wants_write() {
            match self.poll_write_tls(cx) {
                Poll::Ready(Ok(0)) => break,
                Poll::Ready(Ok(_)) => continue,
                Poll::Ready(Err(e)) => return Poll::Ready(Err(e)),
                Poll::Pending => {
                    // If we wrote some data to the TLS session, report success
                    if n > 0 {
                        return Poll::Ready(Ok(n));
                    }
                    return Poll::Pending;
                }
            }
        }

        Poll::Ready(Ok(n))
    }

    fn poll_flush(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<io::Result<()>> {
        // Flush any pending TLS data
        while self.conn.wants_write() {
            match self.poll_write_tls(cx) {
                Poll::Ready(Ok(0)) => break,
                Poll::Ready(Ok(_)) => continue,
                Poll::Ready(Err(e)) => return Poll::Ready(Err(e)),
                Poll::Pending => return Poll::Pending,
            }
        }

        // Flush underlying IO
        Pin::new(&mut self.io).poll_flush(cx)
    }

    fn poll_shutdown(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<io::Result<()>> {
        // Send close_notify if not already done
        if self.state != TlsState::ShuttingDown && self.state != TlsState::Closed {
            self.state = TlsState::ShuttingDown;
            self.conn.send_close_notify();
        }

        // Flush the close_notify
        while self.conn.wants_write() {
            match self.poll_write_tls(cx) {
                Poll::Ready(Ok(0)) => break,
                Poll::Ready(Ok(_)) => continue,
                Poll::Ready(Err(e)) => return Poll::Ready(Err(e)),
                Poll::Pending => return Poll::Pending,
            }
        }

        self.state = TlsState::Closed;

        // Shutdown underlying IO
        Pin::new(&mut self.io).poll_shutdown(cx)
    }
}
