#[cfg(test)]
mod tests {
    use super::*;
    use tokio::io::{AsyncReadExt, AsyncWriteExt};
    use tracing::{info, debug};

    #[tokio::test]
    async fn test_tls_stream_echo() {
        info!("Testing TLS stream echo");

        // Setup test certs (from test files)
        let chain = test_chain();
        let key = test_key();

        let acceptor = TlsAcceptorBuilder::new(chain.clone(), key)
            .build()
            .unwrap();

        let connector = TlsConnectorBuilder::new()
            .add_root_certificates(chain.certs().iter().cloned())
            .build()
            .unwrap();

        let (client_io, server_io) = tokio::io::duplex(8192);

        // Server task
        let server = tokio::spawn(async move {
            let mut stream = acceptor.accept(server_io).await.unwrap();

            let mut buf = [0u8; 1024];
            let n = stream.read(&mut buf).await.unwrap();
            debug!(bytes = n, "Server received");

            stream.write_all(&buf[..n]).await.unwrap();
            stream.flush().await.unwrap();
            stream.shutdown().await.unwrap();
        });

        // Client task
        let client = tokio::spawn(async move {
            let mut stream = connector.connect("localhost", client_io).await.unwrap();

            stream.write_all(b"Hello, TLS!").await.unwrap();
            stream.flush().await.unwrap();

            let mut buf = [0u8; 1024];
            let n = stream.read(&mut buf).await.unwrap();
            debug!(bytes = n, "Client received");

            assert_eq!(&buf[..n], b"Hello, TLS!");
            stream.shutdown().await.unwrap();
        });

        let (server_result, client_result) = tokio::join!(server, client);
        server_result.unwrap();
        client_result.unwrap();

        info!("TLS echo test passed");
    }

